import gzip, json
path = 'sgl-profile-results/1784317987.7958257/1784317987.7977076-TP-0.trace.json.gz'
with gzip.open(path, 'rt') as f:
    data = json.load(f)
events = data['traceEvents']
from collections import Counter
c = Counter()
for e in events:
    if e.get('cat') in ('cpu_op',) and any(k in e.get('name','') for k in ['item','nonzero','local_scalar','is_nonzero']):
        c[e['name']]+=1
for n,ct in c.most_common():
    print(ct,n)
print()
c2 = Counter()
for e in events:
    if e.get('cat')=='gpu_memcpy':
        c2[e['name']]+=1
for n,ct in c2.most_common():
    print(ct,n)
print()
c3 = Counter()
for e in events:
    if e.get('cat')=='cuda_runtime' and 'Memcpy' in e.get('name','') or e.get('name') in ('hipMemcpyWithStream','hipMemcpyAsync'):
        c3[e['name']]+=1
for n,ct in c3.most_common():
    print(ct,n)
"
